CREATE TABLE IF NOT EXISTS baip_geotagged_farmers (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    objectid INTEGER,
    farmer_name TEXT,
    farmer_mobile TEXT,
    globalid TEXT UNIQUE,
    uniquerowid TEXT,
    state TEXT,
    district TEXT,
    subdistrict TEXT,
    gpname TEXT,
    village TEXT,
    age INTEGER,
    gender TEXT,
    female_headed TEXT,
    total_number_family INTEGER,
    social_category TEXT,
    education_level TEXT,
    income_control TEXT,
    annual_income NUMERIC,
    flood_impact TEXT,
    disease_occurrence TEXT,
    pond_insured TEXT,
    latitude NUMERIC(10, 8),
    longitude NUMERIC(11, 8),
    survey_date TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

